#include <stdio.h>
#include <ctype.h>
#include <string.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        getchar(); // consume newline
        char S[1005]; fgets(S, sizeof(S), stdin);
        size_t len = strlen(S);
        if(len && S[len-1]=='\n') S[--len]='\0';
        char email[205]; fgets(email, sizeof(email), stdin);
        len = strlen(email);
        if(len && email[len-1]=='\n') email[--len]='\0';
        // password
        char password[105];
        strncpy(password, S, N);
        password[N]='\0';
        // check digit and special
        int hasDigit=0, hasSpecial=0;
        for(int i=0;i<N;i++){
            if(isdigit((unsigned)password[i])) hasDigit=1;
            else if(!isalnum((unsigned)password[i])) hasSpecial=1;
        }
        // username
        char *at = strchr(email, '@');
        int prefixLen = at ? (int)(at - email) : (int)strlen(email);
        char username[105]; int idx=0;
        for(int i=0;i<prefixLen && idx<N;i++){
            char c = email[i];
            if(isalnum((unsigned)c)){
                username[idx++] = tolower((unsigned)c);
            }
        }
        // if still shorter, pad with 'x'
        while(idx<N) username[idx++]='x';
        username[N]='\0';
        // output
        printf("%s\n", password);
        printf("%s %s\n", hasDigit?"YES":"NO", hasSpecial?"YES":"NO");
        printf("%s\n", username);
    }
    return 0;
}

