#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N; cin.ignore();
        string S; getline(cin, S);
        string email; getline(cin, email);
        // password
        string password = S.substr(0, N);
        bool hasDigit=false, hasSpecial=false;
        for(char c: password){
            if(isdigit(static_cast<unsigned char>(c))) hasDigit=true;
            else if(!isalnum(static_cast<unsigned char>(c))) hasSpecial=true;
        }
        // username
        size_t atPos = email.find('@');
        string prefix = (atPos==string::npos)? email : email.substr(0, atPos);
        string username="";
        for(char c: prefix){
            if(isalnum(static_cast<unsigned char>(c))){
                username.push_back(tolower(static_cast<unsigned char>(c)));
                if((int)username.size()==N) break;
            }
        }
        while((int)username.size()<N) username.push_back('x');
        // output
        cout<<password<<"\n";
        cout<<(hasDigit?"YES":"NO")<<' '<<(hasSpecial?"YES":"NO")<<"\n";
        cout<<username<<"\n";
    }
    return 0;
}

