import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String S = br.readLine();
            String email = br.readLine();
            // password
            String password = S.substring(0, N);
            boolean hasDigit = false, hasSpecial = false;
            for (char c : password.toCharArray()) {
                if (Character.isDigit(c)) hasDigit = true;
                else if (!Character.isLetterOrDigit(c)) hasSpecial = true;
            }
            // username
            int at = email.indexOf('@');
            String prefix = (at == -1) ? email : email.substring(0, at);
            StringBuilder username = new StringBuilder();
            for (char c : prefix.toCharArray()) {
                if (Character.isLetterOrDigit(c)) {
                    username.append(Character.toLowerCase(c));
                    if (username.length() == N) break;
                }
            }
            while (username.length() < N) username.append('x');
            // output
            out.append(password).append('\n');
            out.append(hasDigit ? "YES" : "NO").append(' ').append(hasSpecial ? "YES" : "NO").append('\n');
            out.append(username).append('\n');
        }
        System.out.print(out.toString());
    }
}

