    if (/[0-9]/.test(ch)) hasDigit = true;
    else if (!/[a-zA-Z0-9]/.test(ch)) hasSpecial = true;
  }
  const atPos = email.indexOf('@');
  const prefix = atPos === -1 ? email : email.slice(0, atPos);
  let username = '';
  for (const ch of prefix) {
    if (/[a-zA-Z0-9]/.test(ch)) {
      username += ch.toLowerCase();
      if (username.length === N) break;
    }
  }
  while (username.length < N) username += 'x';
